                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-3 col-span-1 sm:col-span-2">
                      <label className="text-sm font-semibold text-crea-gray-700">Bases de Refer├¬ncia</label>
